// Solar-Beschattung + Aussenlicht (NOAA Sonnenzeiten, Hamburg).
const LOCATION = { lat: 53.55, lon: 10.0 };
const AUSSENLICHT = 'shelly1-E098068CC9EB';

function sunTimes(date, lat, lon) {
    const D2R = Math.PI / 180, R2D = 180 / Math.PI;
    const doy = Math.floor((date - new Date(Date.UTC(date.getFullYear(), 0, 0))) / 86400000);
    const gamma = doy * D2R * 360 / 365;

    const eqTime = 229.18 * (0.000075 + 0.001868 * Math.cos(gamma) - 0.032077 * Math.sin(gamma)
        - 0.014615 * Math.cos(2 * gamma) - 0.040849 * Math.sin(2 * gamma));

    const decl = 0.006918 - 0.399912 * Math.cos(gamma) + 0.070257 * Math.sin(gamma)
        - 0.006758 * Math.cos(2 * gamma) + 0.000907 * Math.sin(2 * gamma)
        - 0.002697 * Math.cos(3 * gamma) + 0.00148 * Math.sin(3 * gamma);

    const cosH = (Math.cos(90.833 * D2R) - Math.sin(lat * D2R) * Math.sin(decl))
        / (Math.cos(lat * D2R) * Math.cos(decl));

    let sunrise, sunset, noon;
    if (cosH > 1) { sunrise = 0; sunset = 24; noon = 12; }
    else if (cosH < -1) { sunrise = 12; sunset = 12; noon = 12; }
    else {
        const ha = Math.acos(cosH) * R2D;
        const noonUTC = 12 - lon / 15 + eqTime / 60;
        sunrise = noonUTC - ha / 15;
        sunset = noonUTC + ha / 15;
        noon = noonUTC;
    }

    const tzOff = -date.getTimezoneOffset() / 60;
    return { sunrise: sunrise + tzOff, sunset: sunset + tzOff, noon: noon + tzOff };
}

const cfg = {
    shadeOnW: 2500,
    shadePos: 50,
    closePos: 0,
    openPos: 100,
    lightOffNightHour: 1,    // ab 01:00 nachts Licht aus
    lightMorningCloudyW: 500  // morgens Licht an wenn PV < 500W (bewoelkt)
};

function decodeSenecValue(data) {
    if (data === undefined || data === null) return NaN;
    if (typeof data === 'number') return data;
    if (typeof data !== 'string') return NaN;
    const tmp = data.split('_');
    if (tmp.length < 2) return Number(data);
    const type = tmp[0], value = tmp[1];
    if (type === 'fl') {
        const buf = Buffer.from(value, 'hex');
        return Math.round(buf.readFloatBE(0) * 100) / 100;
    }
    if (['u8','u1','u3','u6'].includes(type)) return parseInt(value, 16);
    if (['i1','i3','i8'].includes(type)) return parseInt(value, 16);
    return Number(value);
}

const devices = {
    east: [
        {name:'Kueche1',         shelly:'shelly2pmg4-58e6c5324770', closePos: 20, gen:4},  // Gen4, Blumen
        {name:'Kueche2',         shelly:'shellyswitch25-1099F3', closePos: 20},     // Blumen
        {name:'GaesteBad',       shelly:'shellyswitch25-109DA4'},
        {name:'Badezimmer',      shelly:'shellyplus2pm-ecc9ffc14310', gen:2},        // Gen2
        {name:'Arbeitszimmer1',  shelly:'shellyswitch25-10986E'},                    // Gen1
        {name:'Arbeitszimmer2',  shelly:'shelly2pmg4-48f6eedad190', gen:4}
    ],
    west: [
        {name:'Wohnzimmer1',   shelly:'shellyswitch25-10A277'},
        {name:'Wohnzimmer2',   shelly:'shelly2pmg4-58e6c530408c', gen:4},
        {name:'Schlafzimmer1', shelly:'shellyswitch25-F3FDC4'},
        {name:'Schlafzimmer2', shelly:'shellyswitch25-10A1DE'},
        {name:'Schlafzimmer3', shelly:'shellyswitch25-1097AB'},
        {name:'Till',           shelly:'shellyswitch25-109899'},         // 2.OG, Gen1
        {name:'Jan',            shelly:'shelly2pmg4-e8f60a60b50c', gen:4}  // 2.OG, Gen4 (neu)
    ]
};

const energy = msg.payload && msg.payload.ENERGY ? msg.payload.ENERGY : {};
const pvW = decodeSenecValue(energy.GUI_INVERTER_POWER);
const now = new Date();
const hour = now.getHours() + now.getMinutes() / 60;
const sunny = pvW >= cfg.shadeOnW;
const sun = sunTimes(now, LOCATION.lat, LOCATION.lon);

let phase = 'night';
if (hour >= sun.sunrise && hour < sun.noon) phase = 'east';
else if (hour >= sun.noon && hour < sun.sunset) phase = 'west';

let commands = [];
const ts = now.toISOString();

// === Jalousien ===

if (sunny && phase === 'east') {
    for (const d of devices.east) {
        if (d.gen >= 2) {
            commands.push({topic: d.shelly+'/rpc', payload:{id:1, src:'nodered', method:'Cover.GoToPosition', params:{id:0, pos:cfg.shadePos}}});
        } else {
            commands.push({topic:'shellies/'+d.shelly+'/roller/0/command/pos', payload:cfg.shadePos});
        }
    }
    node.warn(ts + ' OST: ' + devices.east.map(d=>d.name).join(',') + ' -> ' + cfg.shadePos + '% (PV=' + pvW.toFixed(0) + 'W)');
}

if (phase === 'west') {
    for (const d of devices.east) {
        if (d.gen >= 2) {
            commands.push({topic: d.shelly+'/rpc', payload:{id:1, src:'nodered', method:'Cover.GoToPosition', params:{id:0, pos:cfg.openPos}}});
        } else {
            commands.push({topic:'shellies/'+d.shelly+'/roller/0/command/pos', payload:cfg.openPos});
        }
    }
    if (sunny) {
        for (const d of devices.west) {
            if (d.gen >= 2) {
                commands.push({topic: d.shelly+'/rpc', payload:{id:1, src:'nodered', method:'Cover.GoToPosition', params:{id:0, pos:cfg.shadePos}}});
            } else {
                commands.push({topic:'shellies/'+d.shelly+'/roller/0/command/pos', payload:cfg.shadePos});
            }
        }
        node.warn(ts + ' WEST: ' + devices.west.map(d=>d.name).join(',') + ' -> ' + cfg.shadePos + '% (PV=' + pvW.toFixed(0) + 'W)');
    }
}

if (phase === 'night') {
    const all = [...devices.east, ...devices.west];
    for (const d of all) {
        const pos = d.closePos !== undefined ? d.closePos : cfg.closePos;
        if (d.gen >= 2) {
            commands.push({topic: d.shelly+'/rpc', payload:{id:1, src:'nodered', method:'Cover.GoToPosition', params:{id:0, pos:pos}}});
        } else {
            commands.push({topic:'shellies/'+d.shelly+'/roller/0/command/pos', payload: pos});
        }
    }
}

// === Aussenlicht ===

const lightTopic = 'shellies/' + AUSSENLICHT + '/relay/0/command';
const isDark = (hour >= sun.sunset) || (hour < sun.sunrise);

if (isDark) {
    // Nacht: Sonnenuntergang -> an, ab lightOffNightHour -> aus
    const beforeMidnight = hour >= sun.sunset;
    const afterMidnightEarly = hour >= 0 && hour < cfg.lightOffNightHour;
    const deepNight = hour >= cfg.lightOffNightHour && hour < sun.sunrise;

    if (deepNight) {
        commands.push({topic: lightTopic, payload: 'off'});
    } else if (beforeMidnight || afterMidnightEarly) {
        commands.push({topic: lightTopic, payload: 'on'});
    }
} else if (phase === 'east' && !sunny && pvW < cfg.lightMorningCloudyW) {
    // Morgens daemmerig/bewoelkt: Licht an
    commands.push({topic: lightTopic, payload: 'on'});
} else if (phase === 'east' && pvW >= cfg.lightMorningCloudyW) {
    // Sonne reicht: Licht aus
    commands.push({topic: lightTopic, payload: 'off'});
}

function fmtHour(h) {
    const hh = Math.floor(h), mm = Math.round((h - hh) * 60);
    return String(hh).padStart(2,'0') + ':' + String(mm).padStart(2,'0');
}

node.status({
    fill: commands.length > 0 ? 'green' : 'blue',
    shape: 'dot',
    text: (commands.length>0?'\u26a1':'·') + ' PV=' + pvW.toFixed(0) + 'W ' + phase
        + ' \u2600' + fmtHour(sun.sunrise) + ' \uD83C\uDF19' + fmtHour(sun.sunset)
        + (sunny?' sonnig':'') + ' | ' + commands.length + ' cmd'
});

if (commands.length === 0) return null;
return [commands];
